const Autocomplete = (() => {
  "use strict";

  const setAttributes = (element, attributes) => {
    for (let attr in attributes) {
      if (attr === "addClass") {
        element.classList.add(attributes[attr]);
      } else if (attr === "removeClass") {
        element.classList.remove(attributes[attr]);
      } else {
        element.setAttribute(attr, attributes[attr]);
      }
    }
  };

  const getTextFromElement = (element, input) => {
    input.value = getFirstChildElement(element).textContent.trim();
  };

  const getFirstChildElement = (element) => element.firstElementChild || element;

  const setScrollPosition = (resultList, resultWrapper) => {
    resultList.scrollTop = resultList.offsetTop - resultWrapper.offsetHeight;
  };

  const setAriaActivedescendant = (element, id) => {
    element.setAttribute("aria-activedescendant", id || "");
  };

  const setScrollPositionOfElement = (element, listId, classGroup, resultList) => {
    const previousSibling = resultList.previousSibling;
    const previousHeight = previousSibling ? previousSibling.offsetHeight : 0;

    if (element.getAttribute("aria-posinset") == "0") {
      resultList.scrollTop = element.offsetTop - getTotalNonGroupHeight(listId, classGroup);
    }

    if (element.offsetTop - previousHeight < resultList.scrollTop) {
      resultList.scrollTop = element.offsetTop - previousHeight;
    } else {
      const elementBottom = element.offsetTop + element.offsetHeight - previousHeight;
      if (elementBottom > resultList.scrollTop + resultList.offsetHeight) {
        resultList.scrollTop = elementBottom - resultList.offsetHeight;
      }
    }
  };

  const getTotalNonGroupHeight = (listId, classGroup) => {
    const elements = document.querySelectorAll(`#${listId} > li:not(.${classGroup})`);
    let totalHeight = 0;
    [].slice.call(elements).map(element => totalHeight += element.offsetHeight);
    return totalHeight;
  };

  const KEYS = {
    ESC: 27,
    ENTER: 13,
    UP: 38,
    DOWN: 40,
    TAB: 9
  };

  class AutocompleteClass {
    constructor(id, config) {
      let {
        delay = 500,
        clearButton = true,
        howManyCharacters = 1,
        selectFirst = false,
        insertToInput = false,
        showAllValues = false,
        cache = false,
        disableCloseOnSelect = false,
        classGroup,
        classPreventClosing,
        classPrefix,
        ariaLabelClear,
        onSearch,
        onResults = () => {},
        onSubmit = () => {},
        onOpened = () => {},
        onReset = () => {},
        onRender = () => {},
        onClose = () => {},
        noResults = () => {},
        onSelectedItem = () => {}
      } = config;

      this.selector = id.startsWith('.') ? id : `#${id}`;
      this.root = document.querySelector(this.selector);
      if (!this.root) {
        console.warn(`[Autocomplete] Cannot find element with selector "${this.selector}"`);
        return;
      }
      this.onSearch = this.wrapOnSearch(onSearch);
      this.onResults = onResults;
      this.onRender = onRender;
      this.onSubmit = onSubmit;
      this.onSelected = onSelectedItem;
      this.onOpened = onOpened;
      this.onReset = onReset;
      this.noResults = noResults;
      this.onClose = onClose;
      this.delay = delay;
      this.characters = howManyCharacters;
      this.clearButton = clearButton;
      this.selectFirst = selectFirst;
      this.toInput = insertToInput;
      this.showAll = showAllValues;
      this.classGroup = classGroup;
      this.prevClosing = classPreventClosing;
      this.clearBtnAriLabel = ariaLabelClear || "clear text from input";
      this.prefix = classPrefix ? `${classPrefix}-auto` : "auto";
      this.disable = disableCloseOnSelect;
      this.cache = cache;
      this.outputUl = `${this.prefix}-${this.id}-results`;
      this.cacheData = `data-cache-auto-${this.id}`;
      this.isLoading = `${this.prefix}-is-loading`;
      this.isActive = `${this.prefix}-is-active`;
      this.activeList = `${this.prefix}-selected`;
      this.selectedOption = `${this.prefix}-selected-option`;
      this.err = `${this.prefix}-error`;
      this.regex = /[|\\{}()[\]^$+*?.]/g;
      this.timeout = null;
      this.resultWrap = document.createElement("div");
      this.resultList = document.createElement("ul");
      this.cBtn = document.createElement("button");

      // Bind methods to this to ensure proper 'this' context
      this.handleInput = this.handleInput.bind(this);
      this.reset = this.reset.bind(this);
      this.searchItem = this.searchItem.bind(this);
      this.onLoading = this.onLoading.bind(this);
      this.handleShowItems = this.handleShowItems.bind(this);
      this.handleMouse = this.handleMouse.bind(this);
      this.handleDocClick = this.handleDocClick.bind(this);
      this.getTextFromLi = this.getTextFromLi.bind(this);
      this.handleKeys = this.handleKeys.bind(this);
      this.destroy = this.destroy.bind(this);

      this.init();
    }

    wrapOnSearch(onSearch) {
      const isPromise = (fn) => Boolean(fn && typeof fn.then === 'function');

      return isPromise(onSearch)
        ? onSearch
        : ({ currentValue, element }) => {
          return Promise.resolve(onSearch({ currentValue, element }));
        };
    }

    init() {
      const { resultList, root } = this;
      this.clearbutton();
      this.createResultsList(root, resultList, this.outputUl, this.resultWrap, this.prefix);
      root.addEventListener("input", this.handleInput);

      if (this.showAll) {
        root.addEventListener("click", this.handleInput);
      }

      this.onRender({ element: root, results: resultList });
    }

    createResultsList(rootElement, resultsList, listId, resultWrapper, classPrefix) {
      setAttributes(resultsList, {
        id: listId,
        tabIndex: "0",
        role: "listbox"
      });

      setAttributes(resultWrapper, {
        addClass: `${classPrefix}-results-wrapper`
      });

      resultWrapper.insertAdjacentElement("beforeend", resultsList);
      rootElement.parentNode.insertBefore(resultWrapper, rootElement.nextSibling);
    }

    cacheAct(action, element) {
      const root = this.root;

      if (!this.cache) return;

      if (action === "update") {
        root.setAttribute(this.cacheData, element.value);
      } else if (action === "remove") {
        root.removeAttribute(this.cacheData);
      } else {
        root.value = root.getAttribute(this.cacheData);
      }
    }

    handleInput(event) {
      let { target, type } = event;

      if (this.root.getAttribute("aria-expanded") === "true" && type === "click") {
        return;
      }

      const value = target.value.replace(this.regex, "\\$&");
      this.cacheAct("update", target);

      const delayTime = this.showAll ? 0 : this.delay;
      clearTimeout(this.timeout);

      this.timeout = setTimeout(() => {
        this.searchItem(value.trim());
      }, delayTime);
    }

    reset() {
      setAttributes(this.root, {
        "aria-owns": `${this.id}-list`,
        "aria-expanded": "false",
        "aria-autocomplete": "list",
        "aria-activedescendant": "",
        role: "combobox",
        removeClass: "auto-expanded"
      });

      this.resultWrap.classList.remove(this.isActive);

      if ((this.matches?.length == 0 && !this.toInput) || this.showAll) {
        this.resultList.innerHTML = "";
      }

      this.index = this.selectFirst ? 0 : -1;
      this.onClose();
    }

    searchItem(term) {
      this.value = term;
      this.onLoading(true);

      this.setupClearButton(term);

      if (this.characters > term.length && !this.showAll) {
        this.onLoading();
        return;
      }

      this.onSearch({ currentValue: term, element: this.root })
        .then(data => {
          const inputLength = this.root.value.length;
          const resultsLength = data.length;

          this.matches = Array.isArray(data) ? [...data] : JSON.parse(JSON.stringify(data));
          this.onLoading();
          this.error();

          this.handleNoResults(term, inputLength, resultsLength);

          if ((resultsLength > 0) || (data && typeof data === 'object' && data.constructor === Object)) {
            this.index = this.selectFirst ? 0 : -1;
            this.results();
            this.events();
          }
        })
        .catch(() => {
          this.onLoading();
          this.reset();
        });
    }

    setupClearButton(term) {
      if (!this.clearButton) return;

      this.showClearButton();

      if (term.length == 0) {
        this.cBtn.classList.add("hidden");
      }
    }

    showClearButton() {
      if (!this.clearButton) return;

      this.cBtn.classList.remove("hidden");
      this.cBtn.addEventListener("click", this.destroy);
    }

    handleNoResults(term, inputLength, resultsLength) {
      if (resultsLength == 0 && inputLength == 0) {
        this.cBtn.classList.add("hidden");
      }

      if (resultsLength == 0 && inputLength) {
        this.root.classList.remove("auto-expanded");
        this.reset();
        this.noResults({ element: this.root, currentValue: term, template: this.results });
        this.events();
      }
    }

    onLoading(isLoading) {
      this.root.parentNode.classList[isLoading ? "add" : "remove"](this.isLoading);
    }

    error() {
      this.root.classList.remove(this.err);
    }

    events() {
      const { root, resultList } = this;

      root.addEventListener("keydown", this.handleKeys);
      root.addEventListener("click", this.handleShowItems);

      ["mousemove", "click"].forEach(eventType => {
        resultList.addEventListener(eventType, this.handleMouse);
      });

      document.addEventListener("click", this.handleDocClick);
    }

    results(template) {
      setAttributes(this.root, {
        "aria-expanded": "true",
        addClass: `${this.prefix}-expanded`
      });

      this.resultList.innerHTML = this.getResultsHTML(template);
      this.resultWrap.classList.add(this.isActive);

      const groupSelector = this.classGroup ? `:not(.${this.classGroup})` : "";
      this.itemsLi = document.querySelectorAll(`#${this.outputUl} > li${groupSelector}`);

      this.selectFirstEl();
      this.onOpened({ type: "results", element: this.root, results: this.resultList });
      this.setRolesForListItems(this.itemsLi);
      setScrollPosition(this.resultList, this.resultWrap);
    }

    getResultsHTML(template) {
      if (this.matches.length === 0) {
        return this.onResults({
          currentValue: this.value,
          matches: 0,
          template
        });
      }

      return this.onResults({
        currentValue: this.value,
        matches: this.matches,
        classGroup: this.classGroup
      });
    }

    setRolesForListItems(items) {
      for (let i = 0; i < items.length; i++) {
        setAttributes(items[i], {
          role: "option",
          tabindex: "-1",
          "aria-selected": "false",
          "aria-setsize": items.length,
          "aria-posinset": i
        });
      }
    }

    handleDocClick(event) {
      let { target } = event;
      let shouldPreventClose = null;

      if ((target.closest("ul") && this.disable) || target.closest(`.${this.prevClosing}`)) {
        shouldPreventClose = true;
      }

      if (target.id === this.id || shouldPreventClose) {
        return;
      }

      this.reset();
    }

    selectFirstEl() {
      const { index, activeList, selectedOption, selectFirst, root } = this;

      this.remAria(document.querySelector(`.${activeList}`));

      if (!selectFirst) return;

      const { firstElementChild } = this.resultList;
      const elementToSelect = this.classGroup && this.matches.length > 0 && selectFirst
        ? firstElementChild.nextElementSibling
        : firstElementChild;

      setAttributes(elementToSelect, {
        id: `${selectedOption}-0`,
        addClass: activeList,
        "aria-selected": "true"
      });

      this.onSelected({ index, element: root, object: this.matches[index] });
      setAriaActivedescendant(root, `${selectedOption}-0`);
    }

    setAttr(element, attributes) {
      for (let attr in attributes) {
        if (attr === "addClass") {
          element.classList.add(attributes[attr]);
        } else if (attr === "removeClass") {
          element.classList.remove(attributes[attr]);
        } else {
          element.setAttribute(attr, attributes[attr]);
        }
      }
    }

    handleShowItems() {
      const { root, resultWrap, resultList, isActive } = this;

      if (resultList.textContent.length <= 0 || resultWrap.classList.contains(isActive)) {
        return;
      }

      setAttributes(root, {
        "aria-expanded": "true",
        addClass: `${this.prefix}-expanded`
      });

      resultWrap.classList.add(isActive);
      setScrollPosition(resultList, resultWrap);
      this.selectFirstEl();
      this.onOpened({ type: "showItems", element: root, results: resultList });
    }

    handleMouse(event) {
      event.preventDefault();

      const { target, type } = event;
      const listItem = target.closest("li");
      const hasRole = listItem?.hasAttribute("role");
      const activeClass = this.activeList;
      const currentActive = document.querySelector(`.${activeClass}`);

      if (!listItem || !hasRole) return;

      if (type === "click") {
        this.getTextFromLi(listItem);
      }

      if (type === "mousemove" && !listItem.classList.contains(activeClass)) {
        this.remAria(currentActive);
        this.setAria(listItem);
        this.index = this.indexLiSelected(listItem);
        this.onSelected({
          index: this.index,
          element: this.root,
          object: this.matches[this.index]
        });
      }
    }

    getTextFromLi(element) {
      const { root, index, disable } = this;

      if (!element || this.matches.length === 0) {
        if (!disable) this.reset();
        return;
      }

      getTextFromElement(element, root);

      this.onSubmit({
        index,
        element: root,
        object: this.matches[index],
        results: this.resultList
      });

      if (!disable) {
        this.remAria(element);
        this.reset();
      }

      if (this.clearButton) {
        this.cBtn.classList.remove("hidden");
      }

      this.cacheAct("remove");
    }

    indexLiSelected(element) {
      return Array.prototype.indexOf.call(this.itemsLi, element);
    }

    handleKeys(event) {
      const { root } = this;
      const { keyCode } = event;
      const isActive = this.resultWrap.classList.contains(this.isActive);
      const totalItems = this.matches.length + 1;

      this.selectedLi = document.querySelector(`.${this.activeList}`);

      switch (keyCode) {
        case KEYS.UP:
        case KEYS.DOWN:
          event.preventDefault();

          if ((totalItems <= 1 && this.selectFirst) || !isActive) {
            return;
          }

          if (keyCode === KEYS.UP) {
            if (this.index < 0) {
              this.index = totalItems - 1;
            }
            this.index -= 1;
          } else {
            this.index += 1;
            if (this.index >= totalItems) {
              this.index = 0;
            }
          }

          this.remAria(this.selectedLi);

          if (totalItems > 0 && this.index >= 0 && this.index < totalItems - 1) {
            this.onSelected({
              index: this.index,
              element: root,
              object: this.matches[this.index]
            });

            this.setAria(this.itemsLi[this.index]);

            if (this.toInput && isActive) {
              getTextFromElement(this.itemsLi[this.index], root);
            }
          } else {
            this.cacheAct();
            setAriaActivedescendant(root);
          }
          break;

        case KEYS.ENTER:
          this.getTextFromLi(this.selectedLi);
          break;

        case KEYS.TAB:
        case KEYS.ESC:
          this.reset();
          break;
      }
    }

    setAria(element) {
      const id = `${this.selectedOption}-${this.indexLiSelected(element)}`;

      setAttributes(element, {
        id,
        "aria-selected": "true",
        addClass: this.activeList
      });

      setAriaActivedescendant(this.root, id);
      setScrollPositionOfElement(element, this.outputUl, this.classGroup, this.resultList);
    }

    remAria(element) {
      if (!element) return;

      setAttributes(element, {
        id: "",
        removeClass: this.activeList,
        "aria-selected": "false"
      });
    }

    clearbutton() {
      if (!this.clearButton) return;

      const { cBtn } = this;

      setAttributes(cBtn, {
        class: `${this.prefix}-clear hidden`,
        type: "button",
        "aria-label": this.clearBtnAriLabel
      });

      this.root.insertAdjacentElement("afterend", cBtn);
    }

    destroy() {
      const { root } = this;

      if (this.clearButton) {
        this.cBtn.classList.add("hidden");
      }

      root.value = "";
      root.focus();
      this.resultList.textContent = "";
      this.reset();
      this.error();
      this.onReset(root);

      root.removeEventListener("keydown", this.handleKeys);
      root.removeEventListener("click", this.handleShowItems);
      document.removeEventListener("click", this.handleDocClick);
    }
  }

  return AutocompleteClass;
})();
window.Autocomplete = Autocomplete;

export default Autocomplete;
